// Parse and validate input
const body = $input.first().json.body ?? $input.first().json;

const {
  patient_id,
  service_id,
  service_name,
  service_color,
  doctor_id,
  doctor_name,
  doctor_email,
  google_calendar_id,
  started_by,
  notes,
  steps
} = body;

if (!patient_id) throw new Error('patient_id is required');
if (!service_id) throw new Error('service_id is required');
if (!doctor_id) throw new Error('doctor_id is required');
if (!Array.isArray(steps) || steps.length === 0) throw new Error('steps array is required');

// Compute date range from calendar steps
const calendarDates = steps
  .filter(s => s.schedule_mode === 'calendar' && s.scheduled_date)
  .map(s => s.scheduled_date)
  .sort();

const expectedEndAt = calendarDates.length > 0 ? calendarDates[calendarDates.length - 1] : null;
const startedAt    = calendarDates.length > 0 ? calendarDates[0] : new Date().toISOString().split('T')[0];

return [{
  json: {
    patient_id,
    service_id,
    service_name,
    service_color: service_color ?? null,
    doctor_id,
    doctor_name: doctor_name ?? null,
    doctor_email: doctor_email ?? null,
    google_calendar_id: google_calendar_id ?? null,
    started_by: started_by ?? doctor_id,
    notes: notes ?? null,
    steps,
    startedAt,
    expectedEndAt
  }
}];

// Retrieve the new sequence ID and build appointment inserts for calendar steps
const sequenceId   = $input.first().json.id;
const parsed       = $('Parse Input').first().json;
const { doctor_id, google_calendar_id, steps } = parsed;

const calendarSteps = steps.filter(s => s.schedule_mode === 'calendar' && s.scheduled_date);
const manualSteps   = steps.filter(s => s.schedule_mode !== 'calendar' || !s.scheduled_date);

const appointmentInserts = calendarSteps.map(step => {
  const startTime  = `${step.scheduled_date}T09:00:00`;
  const durationMs = (step.duration_minutes ?? 60) * 60000;
  const endTime    = new Date(new Date(startTime).getTime() + durationMs).toISOString().replace('T', ' ').substring(0, 19);
  const startFmt   = startTime.replace('T', ' ');
  return {
    sequenceId,
    stepNumber:       step.step_number,
    stepName:         step.step_name,
    scheduledDate:    step.scheduled_date,
    startTime:        startFmt,
    endTime:          endTime,
    patientId:        parsed.patient_id,
    doctorId:         doctor_id,
    googleCalendarId: google_calendar_id,
    notes:            step.notes ?? null
  };
});

return [{
  json: {
    sequenceId,
    calendarSteps,
    manualSteps,
    hasCalendarSteps: calendarSteps.length > 0,
    appointmentInserts,
    parsedPayload: parsed
  }
}];

// Build INSERT using actual appointments table columns
const { appointmentInserts, sequenceId } = $input.first().json;

// Build VALUES rows
const rows = appointmentInserts.map(appt => {
  const notes   = appt.notes ? `'${appt.notes.replace(/'/g, "''")}'` : 'NULL';
  const summary = `'${appt.stepName.replace(/'/g, "''")}'`;
  // calendar_source_id: look up by google_calendar_id (bigint FK)
  const calSrcId = appt.googleCalendarId
    ? `(SELECT id FROM calendar_sources WHERE google_calendar_id = '${appt.googleCalendarId}' LIMIT 1)`
    : 'NULL';
  return `(
    '${appt.patientId}',
    '${appt.startTime}'::timestamp,
    '${appt.endTime}'::timestamp,
    '${appt.doctorId}',
    ${summary},
    ${notes},
    'scheduled',
    ${sequenceId},
    ${appt.stepNumber},
    'pending',
    ${calSrcId}
  )`;
}).join(',\n');

const insertSQL = `
  INSERT INTO appointments (
    patient_id,
    start_datetime,
    end_datetime,
    assignee_id,
    summary,
    notes,
    status,
    sequence_id,
    step_position,
    milestone_status,
    calendar_source_id
  ) VALUES ${rows}
  RETURNING id, step_position;
`;

return [{ json: { ...$input.first().json, insertSQL } }];

// Build final response merging appointment IDs back into steps

// Collect inserted rows: may come from Postgres (id + step_position)
// or be empty when there were no calendar steps (manual-only path)
const pgRows = $input.all();
const apptByStep = {};
pgRows.forEach(row => {
  if (row.json.id && row.json.step_position != null) {
    apptByStep[row.json.step_position] = row.json.id;
  }
});

// Retrieve original data from Prepare Appointments node
const prepNode    = $('Prepare Appointments').first().json;
const { sequenceId, parsedPayload } = prepNode;
const allSteps    = parsedPayload.steps;

const responseSteps = allSteps.map(step => {
  const appointmentId = apptByStep[step.step_number] ?? null;
  return {
    step_number:    step.step_number,
    step_name:      step.step_name,
    scheduled_date: step.scheduled_date ?? null,
    schedule_mode:  step.schedule_mode,
    appointment_id: appointmentId,
    status:         appointmentId ? 'scheduled' : 'pending'
  };
});

return [{
  json: {
    sequence_id:   sequenceId,
    status:        'active',
    service_name:  parsedPayload.service_name,
    service_color: parsedPayload.service_color,
    started_at:    parsedPayload.startedAt,
    steps:         responseSteps
  }
}];
